//! Rust code generator — transforms WorkflowManifest into compilable Rust source.

use crate::manifest::*;
use regex::Regex;

pub fn generate_rust(manifest: &WorkflowManifest) -> String {
    let mut code = String::new();

    // Header
    code.push_str(&format!(
        "// Auto-generated by: vil compile (server mode)\n\
         // Source: {} v{}\n\
         // Endpoints: {}\n\
         // DO NOT EDIT — regenerate from source\n\n",
        manifest.name,
        manifest.vil_version,
        manifest.endpoints.len()
    ));

    code.push_str("#![allow(unused_imports, dead_code)]\n\n");

    // Imports
    code.push_str("use vil_server::prelude::*;\n");
    code.push_str("use vil_server::tracing::Instrument;\n");
    code.push_str("use serde::{Serialize, Deserialize};\n");

    // Check if any endpoint has upstream
    let has_upstream = manifest.endpoints.iter().any(|e| e.upstream.is_some());
    if has_upstream {
        code.push_str("use reqwest;\n");
    }

    // Import error derive if errors are defined
    if !manifest.errors.is_empty() {
        code.push_str("use vil_server::DeriveVilError;\n");
    }

    // Import mesh types if mesh is defined
    if manifest.mesh.is_some() {
        code.push_str("use vil_server::{VxMeshConfig, VxLane};\n");
    }

    // Import failover types if failover is defined (#5)
    if manifest.failover.is_some() {
        code.push_str("use vil_server::{VxFailoverConfig, FailoverStrategy};\n");
    }

    // Import WASM FaaS types if vil_wasm: section declared (#6)
    if !manifest.vil_wasm.is_empty() {
        code.push_str("use vil_capsule::{WasmFaaSConfig, WasmFaaSRegistry, CapsuleInput};\n");
    }

    // Import Sidecar types if sidecars: section declared (#6)
    if !manifest.sidecars.is_empty() {
        code.push_str("use vil_sidecar::{SidecarConfig, SidecarRegistry};\n");
    }

    code.push_str("\n");

    // Generate semantic types (#1)
    if !manifest.semantic_types.is_empty() {
        code.push_str(&generate_semantic_types(&manifest.semantic_types));
    }

    // Generate SSE events (#7)
    if !manifest.sse_events.is_empty() {
        code.push_str(&generate_sse_events(&manifest.sse_events));
    }

    // Generate WebSocket events (#8)
    if !manifest.ws_events.is_empty() {
        code.push_str(&generate_ws_events(&manifest.ws_events));
    }

    // Generate state struct (3.3)
    if let Some(state) = &manifest.state {
        code.push_str(&generate_state_struct(state));
    }

    // Generate input/output structs per endpoint
    for ep in &manifest.endpoints {
        if let Some(input) = &ep.input {
            let struct_name = format!("{}Input", to_pascal_case(&ep.handler));
            code.push_str(&generate_struct(&struct_name, &input.fields, true));
        }
        if let Some(output) = &ep.output {
            let struct_name = format!("{}Output", to_pascal_case(&ep.handler));
            code.push_str(&generate_struct(&struct_name, &output.fields, false));
        }
    }

    // Generate error enum if defined (3.4)
    if !manifest.errors.is_empty() {
        code.push_str(&generate_error_enum(&manifest.name, &manifest.errors));
    }

    // Generate handler functions
    for ep in &manifest.endpoints {
        code.push_str(&generate_handler(ep));
    }

    // Generate entity structs (from entities: section)
    if !manifest.entities.is_empty() {
        code.push_str(
            "// ── Entity Structs (auto-generated from entities: section) ────────────\n\n",
        );
        for entity in &manifest.entities {
            let default_table = entity.name.to_lowercase();
            let _table = entity.table.as_deref().unwrap_or(&default_table);
            let _source = entity.source.as_deref().unwrap_or("default");
            code.push_str(&format!(
                "#[derive(Clone, Debug, Serialize, Deserialize)]\n"
            ));
            code.push_str(&format!("pub struct {} {{\n", to_pascal_case(&entity.name)));
            for f in &entity.fields {
                let rt = rust_type(&f.field_type, &None);
                if f.nullable == Some(true) {
                    code.push_str(&format!("    pub {}: Option<{}>,\n", f.name, rt));
                } else {
                    code.push_str(&format!("    pub {}: {},\n", f.name, rt));
                }
            }
            code.push_str("}\n\n");
        }
    }

    // Generate CRUD handlers for entities
    if !manifest.entities.is_empty() {
        code.push_str(
            "// ── CRUD Handlers (auto-generated from entities: section) ─────────────\n\n",
        );
        code.push_str("use vil_db_sqlx::{MultiPoolManager, SqlxPool};\n\n");
        for entity in &manifest.entities {
            let lower = entity.name.to_lowercase();
            let pascal = to_pascal_case(&entity.name);
            let pool_name = entity.source.as_deref().unwrap_or("primary");

            code.push_str(&format!(r#"
#[vil_endpoint]
async fn list_{lower}(ctx: ServiceCtx) -> Result<VilResponse<Vec<{pascal}>>, VilError> {{
    let pools = ctx.state::<Arc<MultiPoolManager>>().expect("DB pools");
    // TODO: let pool = pools.get("{pool}").unwrap();
    // let rows = sqlx::query_as::<_, {pascal}>("SELECT * FROM {table}").fetch_all(pool.inner()).await?;
    Ok(VilResponse::ok(vec![]))
}}

#[vil_endpoint]
async fn create_{lower}(ctx: ServiceCtx, body: ShmSlice) -> Result<VilResponse<serde_json::Value>, VilError> {{
    let pools = ctx.state::<Arc<MultiPoolManager>>().expect("DB pools");
    let input: {pascal} = body.json().map_err(|_| VilError::bad_request("invalid JSON"))?;
    // TODO: DB insert
    Ok(VilResponse::ok(serde_json::json!({{"id": 1, "status": "created"}})))
}}

#[vil_endpoint]
async fn get_{lower}(ctx: ServiceCtx, Path(id): Path<i64>) -> Result<VilResponse<serde_json::Value>, VilError> {{
    let pools = ctx.state::<Arc<MultiPoolManager>>().expect("DB pools");
    Ok(VilResponse::ok(serde_json::json!({{"id": id}})))
}}

#[vil_endpoint]
async fn delete_{lower}(ctx: ServiceCtx, Path(id): Path<i64>) -> Result<VilResponse<serde_json::Value>, VilError> {{
    let pools = ctx.state::<Arc<MultiPoolManager>>().expect("DB pools");
    Ok(VilResponse::ok(serde_json::json!({{"deleted": true, "id": id}})))
}}
"#, lower = lower, pascal = pascal, pool = pool_name,
   table = entity.table.as_deref().unwrap_or(&lower)));
        }
    }

    // Generate MQ publish/subscribe handler stubs
    if let Some(mq) = &manifest.message_queue {
        if mq.nats.is_some() {
            code.push_str(
                r#"
// ── NATS Handlers (auto-generated, VIL Way) ─────────────────────────────

use vil_mq_nats::NatsClient;

#[vil_endpoint]
async fn nats_publish(
    ctx: ServiceCtx,
    body: ShmSlice,
) -> Result<VilResponse<serde_json::Value>, VilError> {
    let client = ctx.state::<Arc<NatsClient>>().expect("NatsClient");
    let msg: serde_json::Value = body.json().map_err(|_| VilError::bad_request("invalid JSON"))?;
    let subject = msg.get("subject").and_then(|s| s.as_str()).unwrap_or("default");
    let payload = msg.get("payload").and_then(|p| p.as_str()).unwrap_or("{}");
    client.publish(subject, payload.as_bytes()).await.unwrap_or_default();
    Ok(VilResponse::ok(serde_json::json!({"published": true, "subject": subject})))
}
"#,
            );
        }
        if mq.kafka.is_some() {
            code.push_str(
                r#"
// ── Kafka Handlers (auto-generated, VIL Way) ────────────────────────────

use vil_mq_kafka::KafkaProducer;

#[vil_endpoint]
async fn kafka_publish(
    ctx: ServiceCtx,
    body: ShmSlice,
) -> Result<VilResponse<serde_json::Value>, VilError> {
    let producer = ctx.state::<Arc<KafkaProducer>>().expect("KafkaProducer");
    let msg: serde_json::Value = body.json().map_err(|_| VilError::bad_request("invalid JSON"))?;
    let topic = msg.get("topic").and_then(|t| t.as_str()).unwrap_or("default");
    let payload = serde_json::to_vec(&msg).unwrap_or_default();
    let _ = producer.publish(topic, &payload).await;
    Ok(VilResponse::ok(serde_json::json!({"published": true, "topic": topic})))
}
"#,
            );
        }
        if mq.mqtt.is_some() {
            code.push_str(
                r#"
// ── MQTT Handlers (auto-generated, VIL Way) ─────────────────────────────

use vil_mq_mqtt::{MqttClient, QoS};

#[vil_endpoint]
async fn mqtt_publish(
    ctx: ServiceCtx,
    body: ShmSlice,
) -> Result<VilResponse<serde_json::Value>, VilError> {
    let client = ctx.state::<Arc<MqttClient>>().expect("MqttClient");
    let msg: serde_json::Value = body.json().map_err(|_| VilError::bad_request("invalid JSON"))?;
    let topic = msg.get("topic").and_then(|t| t.as_str()).unwrap_or("default");
    let payload = serde_json::to_string(&msg).unwrap_or_default();
    let _ = client.publish(topic, payload.as_bytes(), QoS::AtLeastOnce).await;
    Ok(VilResponse::ok(serde_json::json!({"published": true, "topic": topic})))
}
"#,
            );
        }
    }

    // Generate WebSocket handler if ws_events declared
    if !manifest.ws_events.is_empty() {
        code.push_str(&generate_ws_handler(&manifest.ws_events));
    }

    // Generate SSE handler if sse_events declared
    if !manifest.sse_events.is_empty() {
        code.push_str(&generate_sse_handler(&manifest.sse_events));
    }

    // Generate WASM invoke handler if vil_wasm: declared (#6)
    if !manifest.vil_wasm.is_empty() {
        code.push_str(&generate_wasm_invoke_handler(&manifest.vil_wasm));
    }

    // Generate Sidecar invoke + status handlers if sidecars: declared (#6)
    if !manifest.sidecars.is_empty() {
        code.push_str(&generate_sidecar_handlers(&manifest.sidecars));
    }

    // Generate main
    code.push_str(&generate_main(manifest));

    code
}

/// Parse SHM size string like "64MB", "128mb", "1GB" into bytes.
fn parse_shm_size(s: &str) -> u64 {
    let s = s.trim().to_uppercase();
    if let Some(num) = s.strip_suffix("GB") {
        num.trim().parse::<u64>().unwrap_or(0) * 1024 * 1024 * 1024
    } else if let Some(num) = s.strip_suffix("MB") {
        num.trim().parse::<u64>().unwrap_or(0) * 1024 * 1024
    } else if let Some(num) = s.strip_suffix("KB") {
        num.trim().parse::<u64>().unwrap_or(0) * 1024
    } else {
        s.parse::<u64>().unwrap_or(0)
    }
}

fn capitalize(s: &str) -> String {
    let mut c = s.chars();
    match c.next() {
        None => String::new(),
        Some(f) => f.to_uppercase().to_string() + &c.collect::<String>(),
    }
}

/// Convert a name (possibly with hyphens/dots) into a valid PascalCase Rust identifier.
fn to_pascal_case(s: &str) -> String {
    s.split(|c: char| c == '-' || c == '_' || c == '.')
        .filter(|part| !part.is_empty())
        .map(|part| capitalize(part))
        .collect()
}

fn _to_snake_case(s: &str) -> String {
    s.chars()
        .enumerate()
        .map(|(i, c)| {
            if c.is_uppercase() && i > 0 {
                format!("_{}", c.to_lowercase())
            } else {
                c.to_lowercase().to_string()
            }
        })
        .collect()
}

fn rust_type(field_type: &str, items_type: &Option<String>) -> String {
    match field_type {
        "string" => "String".to_string(),
        "number" | "integer" | "i64" => "i64".to_string(),
        "u8" => "u8".to_string(),
        "u16" => "u16".to_string(),
        "u32" => "u32".to_string(),
        "u64" => "u64".to_string(),
        "i8" => "i8".to_string(),
        "i16" => "i16".to_string(),
        "i32" => "i32".to_string(),
        "f64" | "float" | "double" => "f64".to_string(),
        "f32" => "f32".to_string(),
        "boolean" | "bool" => "bool".to_string(),
        "array" => {
            let inner = items_type.as_deref().unwrap_or("string");
            format!("Vec<{}>", rust_type(inner, &None))
        }
        "object" | "any" => "serde_json::Value".to_string(),
        other => capitalize(other),
    }
}

/// Default value literal for a Rust type
fn rust_default(field_type: &str, items_type: &Option<String>) -> String {
    match field_type {
        "string" => "String::new()".to_string(),
        "number" | "integer" | "i64" => "0".to_string(),
        "u64" => "0".to_string(),
        "f64" | "float" | "double" => "0.0".to_string(),
        "boolean" | "bool" => "false".to_string(),
        "array" => {
            let _ = items_type;
            "Vec::new()".to_string()
        }
        "object" | "any" => "serde_json::Value::Null".to_string(),
        _ => "Default::default()".to_string(),
    }
}

/// Generate the `#[vil_service_state]` struct from manifest state section (3.3)
fn generate_state_struct(state: &StateManifest) -> String {
    let mut s = String::new();
    s.push_str("#[vil_service_state]\n");
    s.push_str("struct AppState {\n");
    for f in &state.fields {
        let rt = rust_type(&f.field_type, &f.items_type);
        s.push_str(&format!("    pub {}: {},\n", f.name, rt));
    }
    s.push_str("}\n\n");
    s
}

fn generate_struct(name: &str, fields: &[FieldManifest], is_input: bool) -> String {
    let mut s = String::new();
    // Both input and output need Deserialize for VilModel (DeserializeOwned bound)
    let derives = "#[derive(Clone, Debug, Serialize, Deserialize, VilModel)]";
    let _ = is_input; // both use same derives now
    s.push_str(&format!("{}\nstruct {} {{\n", derives, name));
    for f in fields {
        let rt = rust_type(&f.field_type, &f.items_type);
        if f.required {
            s.push_str(&format!("    pub {}: {},\n", f.name, rt));
        } else {
            s.push_str(&format!(
                "    #[serde(default)]\n    pub {}: Option<{}>,\n",
                f.name, rt
            ));
        }
    }
    s.push_str("}\n\n");
    s
}

fn generate_error_enum(name: &str, variants: &[ErrorVariant]) -> String {
    let enum_name = format!("{}Error", to_pascal_case(name));
    let mut s = format!("#[derive(Debug, DeriveVilError)]\nenum {} {{\n", enum_name);
    for v in variants {
        let mut attrs = vec![format!("status = {}", v.status)];
        if let Some(code) = &v.code {
            attrs.push(format!("code = \"{}\"", code));
        }
        if let Some(retry) = v.retry {
            attrs.push(format!("retry = {}", retry));
        }
        s.push_str(&format!("    #[vil_error({})]\n", attrs.join(", ")));
        if v.fields.is_empty() {
            s.push_str(&format!("    {},\n", to_pascal_case(&v.name)));
        } else {
            s.push_str(&format!("    {} {{\n", to_pascal_case(&v.name)));
            for f in &v.fields {
                s.push_str(&format!(
                    "        {}: {},\n",
                    f.name,
                    rust_type(&f.field_type, &f.items_type)
                ));
            }
            s.push_str("    },\n");
        }
    }
    s.push_str("}\n\n");
    s
}

fn generate_handler(ep: &EndpointManifest) -> String {
    let fn_name = &ep.handler;
    let has_input = ep.input.is_some();
    let has_output = ep.output.is_some();

    let input_type = format!("{}Input", to_pascal_case(fn_name));
    let output_type = format!("{}Output", to_pascal_case(fn_name));

    // ── Check impl mode first ──
    if let Some(ref imp) = ep.r#impl {
        return match imp.mode.as_str() {
            "inline" => generate_handler_inline(fn_name, imp.code.as_deref().unwrap_or("")),
            "wasm" => generate_handler_wasm(
                fn_name,
                imp.module.as_deref().unwrap_or("handler.wasm"),
                imp.function.as_deref().unwrap_or("handle"),
            ),
            "sidecar" => generate_handler_sidecar(
                fn_name,
                imp.command.as_deref().unwrap_or("echo"),
                imp.protocol.as_deref().unwrap_or("shm"),
                imp.timeout_ms.unwrap_or(5000),
            ),
            "stub" => generate_handler_stub(
                fn_name,
                imp.response.as_deref().unwrap_or(r#"{"ok": true}"#),
            ),
            _ => generate_handler_stub(fn_name, r#"{"ok": true}"#),
        };
    }

    let mut s = String::new();

    // Exec class annotation (#6)
    if ep.exec_class != "AsyncTask" && !ep.exec_class.is_empty() {
        s.push_str(&format!("// exec_class: {}\n", ep.exec_class));
    }
    s.push_str("#[vil_endpoint]\n");

    // Check if SSE upstream
    let is_sse_upstream = ep
        .upstream
        .as_ref()
        .map(|u| u.upstream_type == "sse")
        .unwrap_or(false);

    // Function signature — VIL Way: ServiceCtx + ShmSlice
    let params = if has_input {
        "ctx: ServiceCtx, body: ShmSlice".to_string()
    } else {
        "ctx: ServiceCtx".to_string()
    };
    let ret = if is_sse_upstream {
        // SSE handlers return impl IntoResponse (streaming)
        "Result<axum::response::Response, VilError>".to_string()
    } else if has_output {
        format!("Result<VilResponse<{}>, VilError>", output_type)
    } else {
        "Result<VilResponse<serde_json::Value>, VilError>".to_string()
    };
    s.push_str(&format!("async fn {}({}) -> {} {{\n", fn_name, params, ret));

    // VIL Way: deserialize body from ShmSlice
    if has_input {
        s.push_str(&format!(
            "    let body_data: {} = body.json().map_err(|_| VilError::bad_request(\"invalid JSON\"))?;\n",
            input_type
        ));
    }

    if let Some(upstream) = &ep.upstream {
        let is_sse = upstream.upstream_type == "sse";

        // Generate upstream call
        s.push_str("    let client = reqwest::Client::new();\n");

        // Build body template with interpolation (3.1 template interpolation)
        if let Some(body_tpl) = &upstream.body_template {
            let json_val: serde_json::Value = serde_json::to_value(
                &serde_yaml::from_value::<serde_json::Value>(body_tpl.clone()).unwrap_or_default(),
            )
            .unwrap_or_default();
            let body_json = serde_json::to_string_pretty(&json_val).unwrap_or_default();

            // Find all ${input.X} placeholders
            let placeholders = find_input_placeholders(&body_json);

            if placeholders.is_empty() {
                // No placeholders — static template
                s.push_str(&format!(
                    "    let upstream_body = serde_json::json!({});\n",
                    body_json
                ));
            } else {
                // Replace placeholders with empty strings in the initial json!()
                let sanitized = replace_placeholders_with_empty(&body_json);
                s.push_str(&format!(
                    "    let mut upstream_body = serde_json::json!({});\n",
                    sanitized
                ));
                // Generate post-hoc assignments for each placeholder
                for (json_path, field_name) in &placeholders {
                    s.push_str(&format!(
                        "    upstream_body{} = serde_json::Value::String(body.{}.clone());\n",
                        json_path, field_name
                    ));
                }
            }
        }

        let method = upstream.method.as_deref().unwrap_or("POST");
        s.push_str(&format!(
            "    let resp = client.{}(\"{}\")\n",
            method.to_lowercase(),
            upstream.url
        ));
        if upstream.body_template.is_some() {
            s.push_str("        .json(&upstream_body)\n");
        }
        s.push_str("        .send().await\n");
        s.push_str("        .map_err(|e| VilError::internal(format!(\"Upstream: {}\", e)))?;\n\n");

        if is_sse {
            // SSE streaming: read the byte stream, parse SSE events, extract content
            // and stream back to client via Axum SSE response
            s.push_str("    // SSE streaming response — forward upstream SSE chunks to client\n");
            s.push_str("    use futures::stream::StreamExt;\n");
            s.push_str("    let byte_stream = resp.bytes_stream();\n");
            s.push_str("    let event_stream = byte_stream.map(|chunk| {\n");
            s.push_str("        match chunk {\n");
            s.push_str("            Ok(bytes) => {\n");
            s.push_str("                let text = String::from_utf8_lossy(&bytes);\n");
            s.push_str("                // Parse SSE lines, extract data fields\n");
            s.push_str("                let mut content = String::new();\n");
            s.push_str("                for line in text.lines() {\n");
            s.push_str("                    if let Some(data) = line.strip_prefix(\"data: \") {\n");
            s.push_str("                        if data == \"[DONE]\" { continue; }\n");
            s.push_str("                        if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(data) {\n");

            // Extract content using json_tap pattern from manifest
            // Default: choices[0].delta.content (OpenAI format)
            s.push_str("                            if let Some(c) = parsed[\"choices\"][0][\"delta\"][\"content\"].as_str() {\n");
            s.push_str("                                content.push_str(c);\n");
            s.push_str("                            }\n");

            s.push_str("                        }\n");
            s.push_str("                    }\n");
            s.push_str("                }\n");
            s.push_str("                Ok::<_, std::convert::Infallible>(\n");
            s.push_str("                    axum::response::sse::Event::default().data(content)\n");
            s.push_str("                )\n");
            s.push_str("            }\n");
            s.push_str("            Err(e) => Ok(axum::response::sse::Event::default().data(format!(\"error: {}\", e))),\n");
            s.push_str("        }\n");
            s.push_str("    });\n\n");
            s.push_str("    let sse = axum::response::sse::Sse::new(event_stream)\n");
            s.push_str("        .keep_alive(axum::response::sse::KeepAlive::default());\n");
            s.push_str("    Ok(sse.into_response())\n");
        } else {
            // Non-SSE: parse JSON response
            s.push_str("    let upstream_data: serde_json::Value = resp.json().await\n");
            s.push_str("        .map_err(|e| VilError::internal(format!(\"Parse: {}\", e)))?;\n\n");

            if has_output {
                if let Some(output) = &ep.output {
                    s.push_str(&format!("    Ok(VilResponse::ok({} {{\n", output_type));
                    for f in &output.fields {
                        let extractor = match f.field_type.as_str() {
                            "string" => format!(
                                "upstream_data[\"{}\"].as_str().unwrap_or(\"\").to_string()",
                                f.name
                            ),
                            "number" | "i64" => {
                                format!("upstream_data[\"{}\"].as_i64().unwrap_or(0)", f.name)
                            }
                            "boolean" | "bool" => {
                                format!("upstream_data[\"{}\"].as_bool().unwrap_or(false)", f.name)
                            }
                            _ => format!("upstream_data[\"{}\"].clone()", f.name),
                        };
                        if f.required {
                            s.push_str(&format!("        {}: {},\n", f.name, extractor));
                        } else {
                            s.push_str(&format!("        {}: Some({}),\n", f.name, extractor));
                        }
                    }
                    s.push_str("    }))\n");
                }
            } else {
                s.push_str("    Ok(VilResponse::ok(upstream_data))\n");
            }
        }
    } else {
        // No upstream — simple echo/transform handler
        if has_output {
            s.push_str(&format!("    Ok(VilResponse::ok({} {{\n", output_type));
            if let Some(output) = &ep.output {
                for f in &output.fields {
                    if f.required {
                        s.push_str(&format!("        {}: Default::default(),\n", f.name));
                    } else {
                        s.push_str(&format!("        {}: None,\n", f.name));
                    }
                }
            }
            s.push_str("    }))\n");
        } else {
            s.push_str("    Ok(VilResponse::ok(serde_json::json!({\"status\": \"ok\"})))\n");
        }
    }

    s.push_str("}\n\n");
    s
}

// =============================================================================
// Template interpolation helpers (3.1 — ${input.X} → body.X)
// =============================================================================

/// Represents a placeholder: (JSON path expression like ["messages"][0]["content"], field_name)
type PlaceholderInfo = (String, String);

/// Find all `${input.X}` placeholders in a JSON string.
/// Returns pairs of (JSON indexing path, field_name).
///
/// This works by parsing the JSON, walking the tree, and recording the path
/// to every string value that matches `${input.X}`.
fn find_input_placeholders(json_str: &str) -> Vec<PlaceholderInfo> {
    let re = Regex::new(r#"\$\{input\.(\w+)\}"#).unwrap();
    let val: serde_json::Value = match serde_json::from_str(json_str) {
        Ok(v) => v,
        Err(_) => return vec![],
    };
    let mut results = Vec::new();
    walk_json_for_placeholders(&val, &re, String::new(), &mut results);
    results
}

fn walk_json_for_placeholders(
    val: &serde_json::Value,
    re: &Regex,
    path: String,
    out: &mut Vec<PlaceholderInfo>,
) {
    match val {
        serde_json::Value::String(s) => {
            if let Some(caps) = re.captures(s) {
                let field_name = caps.get(1).unwrap().as_str().to_string();
                out.push((path, field_name));
            }
        }
        serde_json::Value::Array(arr) => {
            for (i, item) in arr.iter().enumerate() {
                let child_path = format!("{}[{}]", path, i);
                walk_json_for_placeholders(item, re, child_path, out);
            }
        }
        serde_json::Value::Object(map) => {
            for (key, item) in map {
                let child_path = format!("{}[\"{}\"]", path, key);
                walk_json_for_placeholders(item, re, child_path, out);
            }
        }
        _ => {}
    }
}

/// Replace all `${input.X}` occurrences in a JSON string with empty strings.
fn replace_placeholders_with_empty(json_str: &str) -> String {
    let re = Regex::new(r#"\$\{input\.\w+\}"#).unwrap();
    re.replace_all(json_str, "").to_string()
}

/// Legacy shim — kept for backwards compatibility but now unused internally.
#[allow(dead_code)]
fn interpolate_template(json_str: &str) -> String {
    let placeholders = find_input_placeholders(json_str);
    if placeholders.is_empty() {
        return json_str.to_string();
    }
    // If placeholders exist, replace them with empty strings (callers use the
    // new two-phase approach instead of this function).
    replace_placeholders_with_empty(json_str)
}

// =============================================================================
// Semantic types codegen (#1)
// =============================================================================

fn generate_semantic_types(types: &[SemanticTypeManifest]) -> String {
    let mut code = String::new();
    for st in types {
        // Check if any field has a non-POD type (String, Vec, etc.)
        // If so, use plain derive instead of strict vil_* macros (VASI layout requires POD only)
        let has_heap_field = st.fields.iter().any(|f| {
            matches!(
                f.field_type.as_str(),
                "string" | "String" | "array" | "object" | "any"
            )
        });

        let macro_attr = if has_heap_field {
            // Use plain derive — safe for serde but not SHM zero-copy
            match st.kind.as_str() {
                "state" => "#[derive(Clone, Debug, Serialize, Deserialize)] // semantic: state (heap fields)",
                "event" => "#[derive(Clone, Debug, Serialize, Deserialize)] // semantic: event (heap fields)",
                "decision" => "#[derive(Clone, Debug, Serialize, Deserialize)] // semantic: decision (heap fields)",
                _ => "#[derive(Clone, Debug, Serialize, Deserialize)]",
            }
        } else {
            match st.kind.as_str() {
                "state" => "#[vil_state]",
                "event" => "#[vil_event]",
                "decision" => "#[vil_decision]",
                _ => "#[derive(Clone, Debug, Serialize, Deserialize)]",
            }
        };

        match st.kind.as_str() {
            "state" | "event" | "decision" => {
                code.push_str(&format!("{}\npub struct {} {{\n", macro_attr, st.name));
                for f in &st.fields {
                    code.push_str(&format!(
                        "    pub {}: {},\n",
                        f.name,
                        rust_type(&f.field_type, &f.items_type)
                    ));
                }
                code.push_str("}\n\n");
            }
            "fault" => {
                code.push_str(&format!("#[vil_fault]\npub enum {} {{\n", st.name));
                for v in &st.variants {
                    code.push_str(&format!("    {},\n", v));
                }
                code.push_str("}\n\n");
            }
            _ => {}
        }
    }
    code
}

// =============================================================================
// Failover codegen (#5)
// =============================================================================

fn generate_failover(failover: &FailoverManifest) -> String {
    let mut s = "    let failover = VxFailoverConfig::new()\n".to_string();
    for e in &failover.entries {
        let strategy = match e.strategy.as_str() {
            "immediate" => "FailoverStrategy::Immediate".to_string(),
            s if s.starts_with("retry:") => {
                let n = s.strip_prefix("retry:").unwrap_or("3");
                format!("FailoverStrategy::Retry({})", n)
            }
            _ => "FailoverStrategy::Retry(3)".to_string(),
        };
        s.push_str(&format!(
            "        .backup(\"{}\", \"{}\", {})\n",
            e.primary, e.backup, strategy
        ));
    }
    s.push_str("    ;\n\n");
    s
}

