fn generate_sse_events(events: &[SseEventManifest]) -> String {
    let mut code = String::new();
    for ev in events {
        let topic_comment = ev
            .topic
            .as_ref()
            .map(|t| format!("/// SSE topic: {}\n", t))
            .unwrap_or_default();
        code.push_str(&format!(
            "{}#[derive(Clone, Debug, Serialize, Deserialize)]\n",
            topic_comment
        ));
        code.push_str(&format!("struct {} {{\n", ev.name));
        for f in &ev.fields {
            code.push_str(&format!(
                "    pub {}: {},\n",
                f.name,
                rust_type(&f.field_type, &f.items_type)
            ));
        }
        code.push_str("}\n\n");
    }
    code
}

