// Module 6: WASM/Sidecar/Script + Code Activity Codegen
// =============================================================================

/// Generate WASM invoke handler for server-mode.
/// POST /wasm/invoke { "module": "name", "function": "fn", "input": {...} }
fn generate_wasm_invoke_handler(wasm_modules: &[WasmModuleManifest]) -> String {
    let mut s = String::new();
    s.push_str(
        "\n// ── WASM FaaS invoke handler ──────────────────────────────────────────────\n\n",
    );

    // Generate module/function inventory as comment
    for wmod in wasm_modules {
        s.push_str(&format!(
            "// Module: {} — functions: [{}]\n",
            wmod.name,
            wmod.functions
                .iter()
                .map(|f| f.name.as_str())
                .collect::<Vec<_>>()
                .join(", ")
        ));
    }

    s.push_str(r#"
#[derive(Deserialize)]
struct WasmInvokeRequest {
    module: String,
    function: String,
    #[serde(default)]
    input: serde_json::Value,
}

#[vil_endpoint]
async fn wasm_invoke(
    ctx: ServiceCtx,
    body: ShmSlice,
) -> VilResponse<serde_json::Value> {
    let registry = ctx.state::<Arc<WasmFaaSRegistry>>().expect("WasmFaaSRegistry");
    let pool = match registry.get(&req.module) {
        Some(p) => p,
        None => return VilResponse::ok(serde_json::json!({
            "error": true, "code": 404,
            "message": format!("WASM module '{}' not found", req.module)
        })),
    };

    let input_bytes = serde_json::to_vec(&req.input).unwrap_or_default();
    let capsule_input = vil_capsule::CapsuleInput {
        function_name: req.function.clone(),
        payload: input_bytes,
    };
    match pool.call(capsule_input) {
        Ok(output) => {
            let result: serde_json::Value = serde_json::from_slice(&output.payload)
                .unwrap_or_else(|_| serde_json::json!({ "raw": String::from_utf8_lossy(&output.payload).to_string() }));
            VilResponse::ok(serde_json::json!({
                "module": req.module,
                "function": req.function,
                "result": result
            }))
        }
        Err(e) => VilResponse::ok(serde_json::json!({
            "error": true, "code": 500,
            "message": format!("WASM execution error: {}", e)
        })),
    }
}
"#);
    s
}

/// Generate Sidecar invoke + status handlers for server-mode.
fn generate_sidecar_handlers(sidecars: &[SidecarManifest]) -> String {
    let mut s = String::new();
    s.push_str(
        "\n// ── Sidecar invoke + status handlers ─────────────────────────────────────\n\n",
    );

    // Comment inventory
    for sc in sidecars {
        s.push_str(&format!(
            "// Sidecar: {} — command: {}\n",
            sc.name,
            sc.command.as_deref().unwrap_or("(self-register)")
        ));
    }

    s.push_str(r#"
#[derive(Deserialize)]
struct SidecarInvokeRequest {
    target: String,
    method: String,
    #[serde(default)]
    data: serde_json::Value,
}

#[vil_endpoint]
async fn sidecar_invoke(
    ctx: ServiceCtx,
    body: ShmSlice,
) -> VilResponse<serde_json::Value> {
    let request_data = serde_json::to_vec(&req.data).unwrap_or_default();

    match vil_sidecar::dispatcher::invoke(&registry, &req.target, &req.method, &request_data).await {
        Ok(response) => {
            let result: serde_json::Value = serde_json::from_slice(&response.data)
                .unwrap_or_else(|_| serde_json::json!({ "raw": String::from_utf8_lossy(&response.data).to_string() }));
            VilResponse::ok(serde_json::json!({
                "target": req.target,
                "method": req.method,
                "result": result,
                "latency_ns": response.latency_ns
            }))
        }
        Err(e) => VilResponse::ok(serde_json::json!({
            "error": true, "code": 500,
            "message": format!("Sidecar error: {}", e)
        })),
    }
}

#[vil_endpoint]
async fn sidecar_status(
    ctx: ServiceCtx,
) -> VilResponse<serde_json::Value> {
    let hub = ctx.state::<Arc<WsHub>>().expect("WsHub");
    let statuses: Vec<serde_json::Value> = registry.status_list().into_iter().map(|(name, health)| {
        serde_json::json!({ "name": name, "health": format!("{:?}", health) })
    }).collect();
    VilResponse::ok(serde_json::json!({ "sidecars": statuses, "total": registry.count() }))
}
"#);
    s
}

// =============================================================================
// Connector init codegen (Phase 6 Stream 3)
// =============================================================================

/// Generate connector/trigger/logging initialization code for injection into main().
fn generate_connector_init(manifest: &WorkflowManifest) -> String {
    let mut code = String::new();

    // Logging init
    if let Some(logging) = &manifest.logging {
        let level = match logging.level.as_str() {
            "trace" => "Trace",
            "debug" => "Debug",
            "info" => "Info",
            "warn" => "Warn",
            "error" => "Error",
            _ => "Info",
        };
        let threads = logging
            .threads
            .map(|t| format!("Some({})", t))
            .unwrap_or("None".into());
        let ring_slots = logging.ring_slots.unwrap_or(1 << 20);

        code.push_str(&format!(
            r#"
    // ── VIL Log System ──
    let _log_task = vil_log::runtime::init_logging(
        vil_log::LogConfig {{
            ring_slots: {},
            level: vil_log::LogLevel::{},
            batch_size: 1024,
            flush_interval_ms: 100,
            threads: {},
        }},
        vil_log::StdoutDrain::resolved(),
    );
"#,
            ring_slots, level, threads
        ));
    }

    // Database connectors
    if let Some(connectors) = &manifest.connectors {
        for db in &connectors.databases {
            let var_name = db.name.replace('-', "_");
            match db.db_type.as_str() {
                "mongo" => {
                    let uri = db.uri.as_deref().unwrap_or("mongodb://localhost:27017");
                    let database = db.database.as_deref().unwrap_or("default");
                    code.push_str(&format!(
                        r#"
    let {var} = vil_db_mongo::process::create_client(vil_db_mongo::MongoConfig {{
        uri: "{}".into(),
        database: "{}".into(),
        ..Default::default()
    }}).await.expect("Failed to connect to MongoDB");
"#,
                        uri,
                        database,
                        var = var_name
                    ));
                }
                "clickhouse" => {
                    let url = db.url.as_deref().unwrap_or("http://localhost:8123");
                    let database = db.database.as_deref().unwrap_or("default");
                    code.push_str(&format!(
                        r#"
    let {var} = vil_db_clickhouse::process::create_client(vil_db_clickhouse::ClickHouseConfig {{
        url: "{}".into(),
        database: "{}".into(),
        ..Default::default()
    }});
"#,
                        url,
                        database,
                        var = var_name
                    ));
                }
                // Additional DB types can be added here: dynamodb, cassandra, timeseries, neo4j, elastic
                _ => {}
            }
        }

        for storage in &connectors.storage {
            let var_name = storage.name.replace('-', "_");
            match storage.storage_type.as_str() {
                "s3" => {
                    let endpoint = storage
                        .endpoint
                        .as_deref()
                        .map(|e| format!("Some(\"{}\".into())", e))
                        .unwrap_or("None".into());
                    let bucket = storage.bucket.as_deref().unwrap_or("default");
                    let region = storage.region.as_deref().unwrap_or("us-east-1");
                    code.push_str(&format!(
                        r#"
    let {var} = vil_storage_s3::process::create_client(vil_storage_s3::S3Config {{
        endpoint: {endpoint},
        bucket: "{}".into(),
        region: "{}".into(),
        ..Default::default()
    }}).await.expect("Failed to connect to S3");
"#,
                        bucket,
                        region,
                        var = var_name,
                        endpoint = endpoint
                    ));
                }
                _ => {}
            }
        }

        for mq in &connectors.queues {
            let var_name = mq.name.replace('-', "_");
            match mq.queue_type.as_str() {
                "rabbitmq" => {
                    let uri = mq.uri.as_deref().unwrap_or("amqp://localhost:5672");
                    code.push_str(&format!(
                        r#"
    let {var} = vil_mq_rabbitmq::process::create_client(vil_mq_rabbitmq::RabbitConfig {{
        uri: "{}".into(),
        ..Default::default()
    }}).await.expect("Failed to connect to RabbitMQ");
"#,
                        uri,
                        var = var_name
                    ));
                }
                _ => {}
            }
        }
    }

    // Triggers
    for trigger in &manifest.triggers {
        let var_name = trigger.name.replace('-', "_");
        match trigger.trigger_type.as_str() {
            "cron" => {
                let schedule = trigger.schedule.as_deref().unwrap_or("0 * * * * *");
                code.push_str(&format!(
                    r#"
    let ({var}_trigger, {var}_rx) = vil_trigger_cron::process::create_cron_trigger(
        vil_trigger_cron::CronConfig {{
            schedule: "{}".into(),
            ..Default::default()
        }}
    ).expect("Failed to create cron trigger");
"#,
                    schedule,
                    var = var_name
                ));
            }
            _ => {}
        }
    }

    code
}

/// Generate Code Activity for a transform node.
/// Dispatches to expr/handler/script/wasm based on CodeManifest.mode.
fn generate_code_activity(node_name: &str, code: &CodeManifest) -> String {
    let mut s = String::new();
    match code.mode.as_str() {
        "expr" => {
            let expr = code.expr.as_deref().unwrap_or("input");
            s.push_str(&format!("    // code: expr → inline expression\n"));
            s.push_str(&format!("    // Transform logic: {}\n", expr));
            s.push_str(&format!(
                "    // (Applied at runtime as: let output = {{ {} }};)\n",
                expr
            ));
        }
        "handler" => {
            let handler_name = code.handler.as_deref().unwrap_or("default_handler");
            s.push_str(&format!("    // code: handler → {}\n", handler_name));
            s.push_str(&format!(
                "    // Requires: src/handlers/{}.rs with fn {}(input: &[u8]) -> Vec<u8>\n",
                handler_name, handler_name
            ));
        }
        "script" => {
            let runtime = code.runtime.as_deref().unwrap_or("lua");
            let rt_crate = if runtime == "js" {
                "vil_script_js"
            } else {
                "vil_script_lua"
            };
            let rt_struct = if runtime == "js" {
                "JsRuntime"
            } else {
                "LuaRuntime"
            };
            s.push_str(&format!(
                "    // code: script ({}) — node: {}\n",
                runtime, node_name
            ));
            if let Some(ref source_inline) = code.source_inline {
                // Inline script
                s.push_str(&format!(
                    "    let {node}_script_runtime = {{\n",
                    node = node_name.replace('-', "_")
                ));
                s.push_str(&format!(
                    "        use {}::{{SandboxConfig, {}}};\n",
                    rt_crate, rt_struct
                ));
                let mut sandbox_str = String::from("SandboxConfig::default()");
                if let Some(ref sb) = code.sandbox {
                    sandbox_str = String::from("SandboxConfig::default()");
                    if let Some(t) = sb.timeout_ms {
                        sandbox_str = format!("{}.timeout_ms({})", sandbox_str, t);
                    }
                    if let Some(m) = sb.max_memory_mb {
                        sandbox_str = format!("{}.max_memory_mb({})", sandbox_str, m);
                    }
                }
                s.push_str(&format!(
                    "        let mut rt = {}::new({});\n",
                    rt_struct, sandbox_str
                ));
                // Escape inline source for Rust string
                let escaped = source_inline
                    .replace('\\', "\\\\")
                    .replace('"', "\\\"")
                    .replace('\n', "\\n");
                s.push_str(&format!("        rt.load_inline(\"{}\");\n", escaped));
                s.push_str("        rt\n");
                s.push_str("    };\n");
            } else if let Some(ref source_path) = code.source {
                // File-based script
                s.push_str(&format!(
                    "    let {node}_script_runtime = {{\n",
                    node = node_name.replace('-', "_")
                ));
                s.push_str(&format!(
                    "        use {}::{{SandboxConfig, {}}};\n",
                    rt_crate, rt_struct
                ));
                s.push_str(&format!(
                    "        let mut rt = {}::new(SandboxConfig::default());\n",
                    rt_struct
                ));
                s.push_str(&format!("        let source = std::fs::read_to_string(\"{}\").expect(\"Failed to read script: {}\");\n",
                    source_path, source_path));
                s.push_str("        rt.load_inline(&source);\n");
                if code.hot_reload == Some(true) {
                    s.push_str(&format!(
                        "        // hot_reload: true — script will be reloaded on change\n"
                    ));
                }
                s.push_str("        rt\n");
                s.push_str("    };\n");
            }
        }
        "wasm" => {
            let module = code.module.as_deref().unwrap_or("unknown");
            let function = code.function.as_deref().unwrap_or("transform");
            s.push_str(&format!(
                "    // code: wasm → {}::{} — node: {}\n",
                module, function, node_name
            ));
            s.push_str(&format!("    // WASM invocation via WasmFaaSRegistry: wasm_registry.get(\"{}\").call_with_memory(\"{}\", input)\n",
                module, function));
        }
        other => {
            s.push_str(&format!(
                "    // code: unknown mode '{}' for node {}\n",
                other, node_name
            ));
        }
    }
    s
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::manifest::WorkflowManifest;

    #[test]
    fn codegen_observer_true_emits_builder_call() {
        let yaml = r#"
vil_version: "6.0.0"
name: test-app
port: 8080
token: shm
observer: true
endpoints:
  - method: GET
    path: /hello
    handler: hello
"#;
        let manifest = WorkflowManifest::from_yaml(yaml).unwrap();
        assert!(manifest.observer, "manifest.observer should be true");
        let code = generate_rust(&manifest);
        assert!(
            code.contains(".observer(true)"),
            "generated code must contain .observer(true)\n---\n{}",
            code
        );
    }

    #[test]
    fn codegen_observer_false_omits_builder_call() {
        let yaml = r#"
vil_version: "6.0.0"
name: test-app
port: 8080
token: shm
endpoints:
  - method: GET
    path: /hello
    handler: hello
"#;
        let manifest = WorkflowManifest::from_yaml(yaml).unwrap();
        assert!(
            !manifest.observer,
            "manifest.observer should default to false"
        );
        let code = generate_rust(&manifest);
        assert!(
            !code.contains(".observer(true)"),
            "generated code must NOT contain .observer(true) when disabled"
        );
    }
}

// =============================================================================
// Handler implementation generators (inline, wasm, sidecar, stub)
// =============================================================================

/// Generate handler with inline Rust code from YAML manifest.
fn generate_handler_inline(fn_name: &str, code: &str) -> String {
    let mut s = String::new();
    s.push_str("#[vil_endpoint]\n");
    s.push_str(&format!(
        "async fn {}(ctx: ServiceCtx, body: ShmSlice) -> Result<VilResponse<serde_json::Value>, VilError> {{\n",
        fn_name
    ));
    // Embed inline code directly
    for line in code.lines() {
        s.push_str(&format!("    {}\n", line));
    }
    s.push_str("}\n");
    s
}

/// Generate handler that delegates to a WASM module.
fn generate_handler_wasm(fn_name: &str, module: &str, function: &str) -> String {
    let mut s = String::new();
    s.push_str("#[vil_endpoint]\n");
    s.push_str(&format!(
        "async fn {}(ctx: ServiceCtx, body: ShmSlice) -> Result<VilResponse<serde_json::Value>, VilError> {{\n",
        fn_name
    ));
    s.push_str(&format!(
        "    // WASM handler: module={}, function={}\n",
        module, function
    ));
    s.push_str(&format!(
        "    let wasm_module = ctx.state::<WasmRuntime>().map_err(|_| VilError::internal(\"WASM runtime not configured\"))?;\n"
    ));
    s.push_str(&format!("    let input_bytes = body.as_bytes();\n"));
    s.push_str(&format!(
        "    let output_bytes = wasm_module.call(\"{}\", \"{}\", input_bytes)\n",
        module, function
    ));
    s.push_str("        .await\n");
    s.push_str(
        "        .map_err(|e| VilError::internal(format!(\"WASM call failed: {}\", e)))?;\n",
    );
    s.push_str("    let result: serde_json::Value = serde_json::from_slice(&output_bytes)\n");
    s.push_str(
        "        .map_err(|e| VilError::internal(format!(\"WASM output not JSON: {}\", e)))?;\n",
    );
    s.push_str("    Ok(VilResponse::ok(result))\n");
    s.push_str("}\n");
    s
}

/// Generate handler that delegates to a sidecar process via SHM or HTTP.
fn generate_handler_sidecar(
    fn_name: &str,
    command: &str,
    protocol: &str,
    timeout_ms: u64,
) -> String {
    let mut s = String::new();
    s.push_str("#[vil_endpoint]\n");
    s.push_str(&format!(
        "async fn {}(ctx: ServiceCtx, body: ShmSlice) -> Result<VilResponse<serde_json::Value>, VilError> {{\n",
        fn_name
    ));
    s.push_str(&format!(
        "    // Sidecar handler: command=\"{}\", protocol={}, timeout={}ms\n",
        command, protocol, timeout_ms
    ));

    if protocol == "shm" {
        s.push_str("    let sidecar = ctx.state::<SidecarPool>().map_err(|_| VilError::internal(\"Sidecar pool not configured\"))?;\n");
        s.push_str(&format!(
            "    let result = sidecar.call_shm(\"{}\", body.as_bytes(), std::time::Duration::from_millis({}))\n",
            fn_name, timeout_ms
        ));
        s.push_str("        .await\n");
        s.push_str(
            "        .map_err(|e| VilError::internal(format!(\"Sidecar call failed: {}\", e)))?;\n",
        );
    } else {
        // HTTP protocol
        s.push_str("    let client = reqwest::Client::new();\n");
        s.push_str(&format!(
            "    let result = client.post(\"http://localhost:0/{}\") // sidecar port resolved at runtime\n",
            fn_name
        ));
        s.push_str("        .body(body.as_bytes().to_vec())\n");
        s.push_str(&format!(
            "        .timeout(std::time::Duration::from_millis({}))\n",
            timeout_ms
        ));
        s.push_str("        .send().await\n");
        s.push_str(
            "        .map_err(|e| VilError::internal(format!(\"Sidecar HTTP failed: {}\", e)))?\n",
        );
        s.push_str("        .bytes().await\n");
        s.push_str(
            "        .map_err(|e| VilError::internal(format!(\"Sidecar read failed: {}\", e)))?;\n",
        );
    }

    s.push_str("    let parsed: serde_json::Value = serde_json::from_slice(&result)\n");
    s.push_str(
        "        .map_err(|e| VilError::internal(format!(\"Sidecar output not JSON: {}\", e)))?;\n",
    );
    s.push_str("    Ok(VilResponse::ok(parsed))\n");
    s.push_str("}\n");
    s
}

/// Generate stub handler that returns a static response.
fn generate_handler_stub(fn_name: &str, response: &str) -> String {
    let mut s = String::new();
    s.push_str("#[vil_endpoint]\n");
    s.push_str(&format!(
        "async fn {}(_ctx: ServiceCtx) -> Result<VilResponse<serde_json::Value>, VilError> {{\n",
        fn_name
    ));
    s.push_str(&format!(
        "    Ok(VilResponse::ok(serde_json::json!({})))\n",
        response
    ));
    s.push_str("}\n");
    s
}
